#!/usr/bin/env python3
"""
Bind AI chat exports into local-only xlsx workbooks.

Supported providers:
- anthropic / claude: expects a Claude export zip or conversations.json
- openai / chatgpt: expects a ChatGPT export zip or conversations.json

Output:
- Sheet1: index / census
- one worksheet per conversation in source order

This script is intentionally local-first. The resulting xlsx files are
expected to remain gitignored and private.
"""

from __future__ import annotations

import argparse
import json
import re
import zipfile
from dataclasses import dataclass
from datetime import UTC, datetime
from pathlib import Path
from tempfile import TemporaryDirectory
from typing import Any

from openpyxl import Workbook


@dataclass
class Message:
    role: str
    text: str
    created_at: str = ""


@dataclass
class Conversation:
    title: str
    created_at: str
    source_id: str
    messages: list[Message]


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Bind Anthropic/OpenAI exports into xlsx workbooks."
    )
    parser.add_argument(
        "--provider",
        required=True,
        choices=["anthropic", "claude", "openai", "chatgpt"],
        help="Export provider to parse.",
    )
    parser.add_argument(
        "--input",
        required=True,
        type=Path,
        help="Path to an export zip or conversations.json file.",
    )
    parser.add_argument(
        "--output",
        required=True,
        type=Path,
        help="Path to the output xlsx workbook.",
    )
    return parser.parse_args()


def load_export_json(input_path: Path) -> Any:
    if input_path.suffix.lower() == ".json":
        return json.loads(input_path.read_text(encoding="utf-8-sig"))

    if input_path.suffix.lower() != ".zip":
        raise ValueError(f"Unsupported input type: {input_path.suffix}")

    with TemporaryDirectory() as tmpdir:
        with zipfile.ZipFile(input_path) as archive:
            archive.extractall(tmpdir)
        extracted = Path(tmpdir)
        matches = list(extracted.rglob("conversations.json"))
        if not matches:
            raise FileNotFoundError("Could not find conversations.json inside zip export")
        return json.loads(matches[0].read_text(encoding="utf-8-sig"))


def safe_sheet_title(raw: str, fallback: str, used: set[str]) -> str:
    title = re.sub(r"[\[\]\*\:/\\\?]", "_", (raw or "").strip())[:31] or fallback
    candidate = title
    counter = 2
    while candidate in used:
        suffix = f"_{counter}"
        candidate = f"{title[:31 - len(suffix)]}{suffix}"
        counter += 1
    used.add(candidate)
    return candidate


def stringify_timestamp(value: Any) -> str:
    if value in (None, ""):
        return ""
    if isinstance(value, (int, float)):
        try:
            return datetime.fromtimestamp(value, UTC).isoformat()
        except Exception:
            return str(value)
    return str(value)


def coerce_text(value: Any) -> str:
    if value is None:
        return ""
    if isinstance(value, str):
        return value.strip()
    if isinstance(value, list):
        parts: list[str] = []
        for item in value:
            if isinstance(item, str):
                parts.append(item)
            elif isinstance(item, dict):
                item_type = item.get("type")
                if item_type == "text":
                    text = item.get("text")
                    if isinstance(text, str):
                        parts.append(text)
                elif isinstance(item.get("text"), str):
                    parts.append(item["text"])
        return "\n".join(part for part in parts if part).strip()
    if isinstance(value, dict):
        if isinstance(value.get("text"), str):
            return value["text"].strip()
        if isinstance(value.get("parts"), list):
            return coerce_text(value["parts"])
    return str(value).strip()


def parse_anthropic_export(data: Any) -> list[Conversation]:
    conversations = data if isinstance(data, list) else data.get("conversations", [])
    result: list[Conversation] = []

    for index, conv in enumerate(conversations, start=1):
        title = conv.get("name") or conv.get("title") or f"Conversation {index}"
        created_at = stringify_timestamp(conv.get("created_at") or conv.get("createdAt"))
        source_id = str(conv.get("uuid") or conv.get("id") or index)
        raw_messages = conv.get("chat_messages") or conv.get("messages") or []
        messages: list[Message] = []

        for raw_msg in raw_messages:
            role = str(raw_msg.get("sender") or raw_msg.get("role") or "unknown")
            text = coerce_text(raw_msg.get("text") or raw_msg.get("content"))
            if not text:
                continue
            msg_created = stringify_timestamp(
                raw_msg.get("created_at") or raw_msg.get("createdAt")
            )
            messages.append(Message(role=role, text=text, created_at=msg_created))

        result.append(
            Conversation(
                title=title,
                created_at=created_at,
                source_id=source_id,
                messages=messages,
            )
        )

    return result


def extract_openai_message_text(message: dict[str, Any]) -> str:
    content = message.get("content")
    if not isinstance(content, dict):
        return ""
    parts = content.get("parts")
    return coerce_text(parts)


def parse_openai_export(data: Any) -> list[Conversation]:
    conversations = data if isinstance(data, list) else data.get("conversations", [])
    result: list[Conversation] = []

    for index, conv in enumerate(conversations, start=1):
        title = conv.get("title") or f"Conversation {index}"
        created_at = stringify_timestamp(conv.get("create_time"))
        source_id = str(conv.get("id") or index)
        mapping = conv.get("mapping") or {}
        rows: list[tuple[float, Message]] = []

        for node in mapping.values():
            if not isinstance(node, dict):
                continue
            message = node.get("message")
            if not isinstance(message, dict):
                continue
            author = message.get("author") or {}
            role = str(author.get("role") or "unknown")
            text = extract_openai_message_text(message)
            if not text:
                continue
            msg_time = message.get("create_time") or node.get("create_time") or 0
            rows.append(
                (
                    float(msg_time or 0),
                    Message(
                        role=role,
                        text=text,
                        created_at=stringify_timestamp(msg_time),
                    ),
                )
            )

        rows.sort(key=lambda item: item[0])
        result.append(
            Conversation(
                title=title,
                created_at=created_at,
                source_id=source_id,
                messages=[message for _, message in rows],
            )
        )

    return result


def build_workbook(provider: str, conversations: list[Conversation], output_path: Path) -> None:
    workbook = Workbook()
    index = workbook.active
    index.title = "Sheet1"
    index.append([provider.capitalize()])
    index.append([f"Bound on {datetime.now(UTC).isoformat()}"])
    index.append(["title", "created_at", "messages", "source_id"])

    used_titles = {"Sheet1"}
    for conv in conversations:
        index.append([conv.title, conv.created_at, len(conv.messages), conv.source_id])
        sheet = workbook.create_sheet(
            safe_sheet_title(conv.title, f"Conversation_{len(workbook.sheetnames)}", used_titles)
        )
        sheet.append([provider.capitalize()])
        sheet.append([conv.title])
        if conv.created_at:
            sheet.append([f"Created: {conv.created_at}"])
        sheet.append([])
        for message in conv.messages:
            header = message.role.title()
            if message.created_at:
                header = f"{header} ({message.created_at})"
            sheet.append([header])
            for line in (message.text.splitlines() or [""]):
                sheet.append([line])
            sheet.append([])

    output_path.parent.mkdir(parents=True, exist_ok=True)
    workbook.save(output_path)


def main() -> None:
    args = parse_args()
    provider = args.provider.lower()
    data = load_export_json(args.input)

    if provider in {"anthropic", "claude"}:
        conversations = parse_anthropic_export(data)
        provider_name = "Claudius"
    else:
        conversations = parse_openai_export(data)
        provider_name = "Codices"

    build_workbook(provider_name, conversations, args.output)
    print(f"bound: {args.output}")
    print(f"conversations: {len(conversations)}")


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Generate a weekly branch garden report."""

from __future__ import annotations

import argparse
import json
import os
import subprocess
import sys
from datetime import datetime, timezone
from pathlib import Path


def run_text(cmd: list[str]) -> str:
    result = subprocess.run(cmd, check=True, capture_output=True, text=True)
    return result.stdout.strip()


def run_json(cmd: list[str]) -> object:
    result = subprocess.run(cmd, check=True, capture_output=True, text=True)
    return json.loads(result.stdout)


def branch_age_days(branch: str) -> int:
    ts = run_text(["git", "log", "-1", "--format=%ct", f"origin/{branch}"])
    now = datetime.now(timezone.utc).timestamp()
    return int((now - int(ts)) // 86400)


def main() -> int:
    parser = argparse.ArgumentParser()
    parser.add_argument("--report-path", type=Path, required=True)
    parser.add_argument("--stale-days", type=int, default=7)
    parser.add_argument("--stale-behind", type=int, default=100)
    args = parser.parse_args()

    branches_raw = run_text(["git", "ls-remote", "--heads", "origin"])
    branches = []
    for line in branches_raw.splitlines():
        if not line.strip():
            continue
        _, ref = line.split("\t", 1)
        branch = ref.replace("refs/heads/", "")
        if branch == "main":
            continue
        branches.append(branch)

    open_prs = run_json(
        [
            "gh",
            "pr",
            "list",
            "--state",
            "open",
            "--json",
            "number,headRefName,title,url",
        ]
    )
    pr_by_head = {pr["headRefName"]: pr for pr in open_prs}

    findings: list[str] = []
    inventory: list[str] = []
    for branch in sorted(branches):
        ahead = int(run_text(["git", "rev-list", f"origin/main..origin/{branch}", "--count"]) or "0")
        behind = int(run_text(["git", "rev-list", f"origin/{branch}..origin/main", "--count"]) or "0")
        age_days = branch_age_days(branch)
        pr = pr_by_head.get(branch)
        if pr:
            inventory.append(
                f"- `{branch}` — open PR #{pr['number']}, {ahead} ahead / {behind} behind, {age_days}d old"
            )
            continue

        inventory.append(f"- `{branch}` — no PR, {ahead} ahead / {behind} behind, {age_days}d old")
        if ahead == 0:
            findings.append(f"- `{branch}` is a zombie branch: no PR and 0 commits ahead of `main`.")
        elif behind >= args.stale_behind:
            findings.append(
                f"- `{branch}` is far behind `main`: {behind} commits behind with no PR."
            )
        elif age_days >= args.stale_days:
            findings.append(f"- `{branch}` is stale: no PR and {age_days} days old.")

    lines = [
        "# Branch Garden Report",
        "",
        f"Remote branches outside trunk: {len(branches)}",
        "",
    ]
    if findings:
        lines.extend(["## Findings", "", *findings, ""])
    else:
        lines.extend(["No branch-garden findings. The tree is tidy.", ""])

    if inventory:
        lines.extend(["## Inventory", "", *inventory, ""])

    args.report_path.write_text("\n".join(lines) + "\n", encoding="utf-8")

    github_output = os.environ.get("GITHUB_OUTPUT")
    if github_output:
        with open(github_output, "a", encoding="utf-8") as fh:
            fh.write(f"has_findings={'true' if bool(findings) else 'false'}\n")
            fh.write(f"branch_count={len(branches)}\n")

    return 0


if __name__ == "__main__":
    sys.exit(main())

